pub fn new() -> Self {
    let fallback = Route::new(service_fn(|_: Request| async {
        Ok(StatusCode::METHOD_NOT_ALLOWED)
    }));

    Self {
        get: MethodEndpoint::None,
        head: MethodEndpoint::None,
