pub(crate) fn encodings<'a>(
    headers: &'a http::HeaderMap,
    supported_encoding: impl SupportedEncodings + 'a,
) -> impl Iterator<Item = (Encoding, QValue)> + 'a {
    headers
        .get_all(http::header::ACCEPT_ENCODING)
        .iter()
        .filter_map(|hval| hval.to_str().ok())
        .flat_map(|s| s.split(','))
        .filter_map(move |v| {
            let mut v = v.splitn(2, ';');

            let encoding = match Encoding::parse(v.next().unwrap().trim(), supported_encoding) {
                Some(encoding) => encoding,
                None => return None, // ignore unknown encodings
            };

            let qval = if let Some(qval) = v.next() {
                QValue::parse(qval.trim())?
            } else {
                QValue::one()
            };

            Some((encoding, qval))
        })
}

fn wildcard_qvalue(headers: &http::HeaderMap) -> Option<QValue> {
    headers
        .get_all(http::header::ACCEPT_ENCODING)
        .iter()
        .filter_map(|hval| hval.to_str().ok())
        .flat_map(|s| s.split(','))
        .find_map(|v| {
            let mut v = v.splitn(2, ';');
            let coding = v.next().unwrap().trim();
            if coding != "*" {
                return None;
            }
            let qval = if let Some(qval) = v.next() {
                QValue::parse(qval.trim())?
            } else {
                QValue::one()
            };
            Some(qval)
        })
}

fn try_new_req_multipart(
    path: &str,
    accepts: &str,
    body: Self::FormData,
    method: Method,
) -> Result<Self, E> {
    match method {
        Method::POST => CLIENT.post(path),
        Method::PUT => CLIENT.put(path),
        Method::PATCH => CLIENT.patch(path),
        m => {
            return Err(E::from_server_fn_error(
                ServerFnErrorErr::UnsupportedRequestMethod(m.to_string()),
            ))
        }
    }
    .header(ACCEPT, accepts)
    .multipart(body)
    .build()
    .map_err(|e| ServerFnErrorErr::Request(e.to_string()).into_app_error())
}

